 1	import React, { MouseEvent, ReactEventHandler } from 'react';
 2	
 3	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { NumberInput, SelectOption, Split } from '@patternfly/react-core';
 6	
 7	import { dropdownUnits } from '../utils/consts';
 8	
 9	const UploadPVCFormSize = ({
10	  requestSizeUnit,
11	  requestSizeValue,
12	  setRequestSizeUnit,
13	  setRequestSizeValue,
14	}) => {
15	  const { t } = useKubevirtTranslation();
16	
17	  const handleRequestSizeInputChange = (obj: { unit: string; value: number }) => {
18	    setRequestSizeValue(obj?.value);
19	    setRequestSizeUnit(obj?.unit);
20	  };
21	
22	  const onValueChange: ReactEventHandler<HTMLInputElement> = (event) => {
23	    handleRequestSizeInputChange({
24	      unit: requestSizeUnit,
25	      value: Number(event?.currentTarget?.value),
26	    });
27	  };
28	
29	  const changeValueBy = (changeBy: number) => {
30	    // When default defaultRequestSizeValue is not set, value becomes NaN and increment decrement buttons of NumberSpinner don't work.
31	    const newValue = Number.isFinite(requestSizeValue) ? requestSizeValue + changeBy : 0 + changeBy;
32	    handleRequestSizeInputChange({ unit: requestSizeUnit, value: newValue });
33	  };
34	
35	  const onUnitChange = (event: MouseEvent<HTMLInputElement>, value: string) => {
36	    handleRequestSizeInputChange({
37	      unit: value,
38	      value: requestSizeValue,
39	    });
40	  };
41	
42	  return (
43	    <>
44	      <label className="control-label co-required" htmlFor="request-size-input">
45	        {t('Size')}
46	      </label>
47	      <Split hasGutter>
48	        <div className="co-m-number-spinner">
49	          <NumberInput
50	            id="request-size-input"
51	            min={1}
52	            minusBtnAriaLabel={t('Decrement')}
53	            name="requestSizeValue"
54	            onChange={onValueChange}
55	            onMinus={() => changeValueBy(-1)}
56	            onPlus={() => changeValueBy(1)}
57	            plusBtnAriaLabel={t('Increment')}
58	            required
59	            value={requestSizeValue}
60	          />
61	        </div>
62	        <FormPFSelect
63	          onSelect={onUnitChange}
64	          selected={requestSizeUnit}
65	          selectedLabel={dropdownUnits[requestSizeUnit]}
66	        >
67	          {Object.entries(dropdownUnits)?.map(([value, label]) => (
68	            <SelectOption key={value} value={value}>
69	              {label}
70	            </SelectOption>
71	          ))}
72	        </FormPFSelect>
73	      </Split>
74	      <p className="help-block" id="request-size-help">
75	        {t(
76	          'Ensure your PVC size covers the requirements of the uncompressed image and any other space requirements.',
77	        )}
78	      </p>
79	    </>
80	  );
81	};
82	
83	export default UploadPVCFormSize;

